import React, { useState, useEffect } from 'react';
import { 
  Card, 
  CardMedia, 
  CardContent, 
  Typography, 
  Button, 
  Box, 
  LinearProgress, 
  Chip, 
  useTheme, 
  Tooltip, 
  Badge, 
  IconButton,
  Avatar,
  Divider,
  Paper
} from '@mui/material';
import { styled, alpha } from '@mui/material/styles';
import { 
  CalendarMonth, 
  Person, 
  Speed, 
  ArrowForward, 
  LocalOffer, 
  Favorite, 
  FavoriteBorder,
  CheckCircle,
  HourglassEmpty,
  NewReleases,
  Close,
  Smartphone,
  SportsEsports,
  CardGiftcard,
  PeopleAlt,
  Sell
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import { format, isAfter, addDays } from 'date-fns';
import { ru } from 'date-fns/locale';
import { useFirebase } from '../../context/FirebaseContext';

// Обновленные стили для карточки
const MotionCard = styled(motion.div)(({ theme }) => ({
  borderRadius: 24,
  overflow: 'visible',
  width: '100%',
  marginBottom: 20,
  transition: 'all 0.3s ease-in-out',
  height: '100%',
}));

const StyledCard = styled(Card)(({ theme }) => ({
  borderRadius: 24,
  overflow: 'hidden',
  height: '100%',
  display: 'flex',
  flexDirection: 'column',
  backgroundColor: theme.palette.background.paper,
  boxShadow: theme.palette.mode === 'light' 
    ? '0 10px 30px rgba(0,0,0,0.08)'
    : '0 10px 30px rgba(0,0,0,0.2)',
  transition: 'all 0.3s ease-in-out',
  position: 'relative',
  '&:hover': {
    boxShadow: theme.palette.mode === 'light' 
      ? '0 16px 40px rgba(0,0,0,0.12)'
      : '0 16px 40px rgba(0,0,0,0.3)',
    transform: 'translateY(-8px)',
  }
}));

const CardDetailsContainer = styled(CardContent)(({ theme }) => ({
  padding: theme.spacing(3, 3, 2, 3),
  flex: 1,
  display: 'flex',
  flexDirection: 'column',
}));

const InfoRow = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  marginRight: theme.spacing(3),
  '& svg': {
    marginRight: theme.spacing(0.7),
    fontSize: 18,
    color: theme.palette.text.secondary,
  }
}));

const BuyButton = styled(Button)(({ theme }) => ({
  borderRadius: 100,
  padding: theme.spacing(1.2, 3),
  fontWeight: 600,
  textTransform: 'none',
  boxShadow: '0 6px 16px rgba(33, 150, 243, 0.25)',
  transition: 'all 0.2s ease-in-out',
  background: theme.palette.primary.main && theme.palette.primary.dark
    ? `linear-gradient(90deg, ${theme.palette.primary.main} 0%, ${theme.palette.primary.dark} 100%)`
    : 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
  '&:hover': {
    boxShadow: '0 8px 20px rgba(33, 150, 243, 0.35)',
    transform: 'translateY(-2px)',
  }
}));

const ProgressLabel = styled(Box)(({ theme }) => ({
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  width: '100%',
  marginTop: theme.spacing(0.8),
  marginBottom: theme.spacing(2),
}));

const PriceChip = styled(Chip)(({ theme }) => ({
  fontWeight: 700,
  background: theme.palette.primary.main && theme.palette.primary.dark
    ? `linear-gradient(90deg, ${theme.palette.primary.main} 0%, ${theme.palette.primary.dark} 100%)`
    : 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
  color: 'white',
  position: 'absolute',
  top: 16,
  right: 66,
  borderRadius: 16,
  boxShadow: '0 6px 16px rgba(33, 150, 243, 0.3)',
  backdropFilter: 'blur(8px)',
  zIndex: 2,
  padding: '8px 16px',
  height: 'auto',
  fontSize: '1rem'
}));

const StatusBadge = styled(Box, {
  shouldForwardProp: (prop) => prop !== 'color'
})<{ color?: string }>(({ theme, color }) => ({
  position: 'absolute',
  top: 16,
  left: 16,
  backgroundColor: alpha(color || theme.palette.error.main, 0.9),
  color: 'white',
  padding: theme.spacing(0.5, 1.5),
  borderRadius: 16,
  fontWeight: 600,
  fontSize: '0.75rem',
  zIndex: 2,
  boxShadow: `0 6px 16px ${alpha(color || theme.palette.error.main, 0.3)}`,
  backdropFilter: 'blur(8px)',
  display: 'flex',
  alignItems: 'center',
  '& .MuiSvgIcon-root': {
    fontSize: '0.875rem',
    marginRight: theme.spacing(0.5)
  }
}));

const CardMediaWrapper = styled(Box)(({ theme }) => ({
  position: 'relative',
  height: 200,
  overflow: 'hidden',
  backgroundColor: alpha(theme.palette.primary.light, 0.05),
  '&::after': {
    content: '""',
    position: 'absolute',
    bottom: 0,
    left: 0,
    right: 0,
    height: '30%',
    background: `linear-gradient(to top, ${theme.palette.background.paper}, transparent)`,
    zIndex: 1,
    opacity: 0.7,
  }
}));

const StyledCardMedia = styled('img')(({ theme }) => ({
  height: '100%',
  width: '100%',
  objectFit: 'cover',
  transition: 'transform 0.7s ease-in-out',
  '&:hover': {
    transform: 'scale(1.08)',
  },
}));

const DetailsButton = styled(Button)(({ theme }) => ({
  textTransform: 'none',
  fontWeight: 600,
  padding: theme.spacing(1, 2),
  borderRadius: 100,
  borderColor: alpha(theme.palette.primary.main, 0.5),
  color: theme.palette.primary.main,
  '&:hover': {
    backgroundColor: alpha(theme.palette.primary.main, 0.05),
    borderColor: theme.palette.primary.main,
    transform: 'translateY(-2px)',
  }
}));

const CompanyLogo = styled(Avatar)(({ theme }) => ({
  position: 'absolute',
  bottom: -20,
  left: 20,
  width: 40,
  height: 40,
  border: `3px solid ${theme.palette.background.paper}`,
  boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
  zIndex: 3,
}));

const FavoriteButton = styled(IconButton)(({ theme }) => ({
  position: 'absolute',
  top: 16,
  right: 16,
  backgroundColor: alpha(theme.palette.background.paper, 0.85),
  backdropFilter: 'blur(8px)',
  '&:hover': {
    backgroundColor: alpha(theme.palette.background.paper, 0.95),
    transform: 'scale(1.1)',
  },
  zIndex: 2,
  width: 38,
  height: 38,
  boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
  transition: 'all 0.2s ease-in-out',
}));

const IconContainer = styled(Box)(({ theme }) => ({
  position: 'absolute',
  bottom: 16,
  right: 16,
  backgroundColor: alpha(theme.palette.background.paper, 0.85),
  backdropFilter: 'blur(8px)',
  borderRadius: '50%',
  width: 38,
  height: 38,
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
  zIndex: 2
}));

const InfoChip = styled(Chip)(({ theme }) => ({
  height: 28,
  fontSize: '0.75rem',
  fontWeight: 600,
  borderRadius: 14,
  backgroundColor: alpha(theme.palette.primary.main, 0.1),
  color: theme.palette.primary.main,
  marginRight: theme.spacing(1),
  marginBottom: theme.spacing(1),
  '& .MuiChip-icon': {
    fontSize: '1rem',
    color: theme.palette.primary.main,
  }
}));

interface CarCardProps {
  id: string;
  title: string;
  image?: string | null;
  description: string;
  ticketsSold: number;
  totalTickets: number;
  price: number;
  year: number;
  participants: number;
  endDate: string;
  status?: 'active' | 'completed' | 'canceled' | 'draft';
  companyId?: string;
  createdAt?: any;
  isFavorite?: boolean;
  toggleFavorite?: (id: string) => Promise<void>;
  itemType?: 'cars' | 'phones' | 'consoles' | 'other';
}

const CarCard: React.FC<CarCardProps> = ({
  id,
  title,
  image,
  description,
  ticketsSold,
  totalTickets,
  price,
  year,
  participants,
  endDate,
  status = 'active',
  companyId,
  createdAt,
  isFavorite = false,
  toggleFavorite,
  itemType = 'cars'
}) => {
  const progress = (ticketsSold / totalTickets) * 100;
  const formattedPrice = new Intl.NumberFormat('ru-RU').format(price);
  const theme = useTheme();
  const [favorite, setFavorite] = useState(isFavorite);
  const [imageError, setImageError] = useState(false);
  
  // Получаем компании и настройки из Firebase Context
  const { companies, appSettings } = useFirebase();
  
  // Находим компанию по ID
  const company = companies.find(c => c.id === companyId);
  
  // Определяем основной цвет на основе компании или настроек
  const primaryColor = company?.color || (appSettings?.primaryColor || theme.palette.primary.main);
  
  // Проверка на скорое завершение (если осталось меньше 20% билетов)
  const isEndingSoon = progress > 80;
  
  // Проверка, новый ли розыгрыш (создан менее 7 дней назад)
  const isNew = createdAt && isAfter(new Date(), addDays(new Date(createdAt.toDate()), -7));
  
  // Форматируем дату окончания
  const formattedEndDate = typeof endDate === 'string' 
    ? endDate.includes('-') 
      ? format(new Date(endDate), 'd MMM yyyy', { locale: ru })
      : endDate
    : 'Не указано';
  
  // Определяем цвет прогресс-бара в зависимости от заполнения
  const getProgressColor = () => {
    if (progress < 40) return alpha(primaryColor || theme.palette.primary.main, 0.9);
    if (progress < 80) return alpha(theme.palette.warning.main, 0.9);
    return alpha(theme.palette.error.main, 0.9);
  };

  // Получаем информацию о статусе для отображения
  const getStatusInfo = () => {
    switch (status) {
      case 'active':
        if (isEndingSoon) return { 
          label: 'Осталось мало билетов', 
          color: theme.palette.error.main,
          icon: <Speed fontSize="small" />
        };
        if (isNew) return {
          label: 'Новый розыгрыш',
          color: theme.palette.success.main,
          icon: <NewReleases fontSize="small" />
        }
        return null;
      case 'completed':
        return { 
          label: 'Завершен', 
          color: theme.palette.success.main,
          icon: <CheckCircle fontSize="small" />
        };
      case 'canceled':
        return { 
          label: 'Отменен', 
          color: theme.palette.error.dark,
          icon: <Close fontSize="small" />
        };
      case 'draft':
        return { 
          label: 'Черновик', 
          color: alpha(theme.palette.text.secondary, 0.9),
          icon: <HourglassEmpty fontSize="small" />
        };
      default:
        return null;
    }
  };

  const statusInfo = getStatusInfo();

  // Обновляем обработчик клика по кнопке избранного
  const handleFavoriteClick = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    
    setFavorite(!favorite);
    
    if (toggleFavorite) {
      toggleFavorite(id);
    }
  };

  // Получаем иконку в зависимости от типа приза
  const getItemTypeIcon = () => {
    switch (itemType) {
      case 'cars':
        return <Speed fontSize="small" />;
      case 'phones':
        return <Smartphone fontSize="small" />;
      case 'consoles':
        return <SportsEsports fontSize="small" />;
      case 'other':
      default:
        return <CardGiftcard fontSize="small" />;
    }
  };

  // Получаем настройки карточек из appSettings
  const cardSettings = appSettings?.cardSettings || {
    enableFavorites: true,
    showCompanyLogo: true,
    showPrice: true,
    showProgress: true,
    cornerRadius: '24px',
    enableHoverEffects: true,
    cardElevation: 'medium'
  };

  // Определяем уровень тени на основе настроек
  const getElevation = () => {
    switch(cardSettings.cardElevation) {
      case 'low': return theme.palette.mode === 'light' 
        ? '0 6px 16px rgba(0,0,0,0.06)'
        : '0 6px 16px rgba(0,0,0,0.18)';
      case 'high': return theme.palette.mode === 'light' 
        ? '0 20px 50px rgba(0,0,0,0.15)'
        : '0 20px 50px rgba(0,0,0,0.3)';
      case 'medium':
      default: return theme.palette.mode === 'light' 
        ? '0 12px 36px rgba(0,0,0,0.1)'
        : '0 12px 36px rgba(0,0,0,0.25)';
    }
  };

  // Функция для отображения запасного изображения в зависимости от типа приза
  const getFallbackImage = () => {
    switch (itemType) {
      case 'cars':
        return 'https://i.imgur.com/Nt3uBqI.jpg'; // URL запасного изображения машины
      case 'phones':
        return 'https://i.imgur.com/dDPEvDM.jpg'; // URL запасного изображения телефона
      case 'consoles':
        return 'https://i.imgur.com/1rI0mMY.jpg'; // URL запасного изображения консоли
      case 'other':
      default:
        return 'https://i.imgur.com/JXRBRbV.jpg'; // URL общего запасного изображения
    }
  };

  // Анимация для карточки
  const cardVariants = {
    initial: { opacity: 0, y: 30 },
    animate: { opacity: 1, y: 0 },
    transition: { duration: 0.5, ease: "easeOut" },
    whileHover: { scale: cardSettings.enableHoverEffects ? 1.02 : 1 }
  };

  return (
    <MotionCard
      initial="initial"
      animate="animate"
      transition={cardVariants.transition}
      whileHover={cardVariants.whileHover}
    >
      <StyledCard sx={{
        borderRadius: cardSettings.cornerRadius || '24px',
        boxShadow: getElevation(),
        '&:hover': {
          boxShadow: cardSettings.enableHoverEffects 
            ? theme.palette.mode === 'light' 
              ? '0 20px 50px rgba(0,0,0,0.15)'
              : '0 20px 50px rgba(0,0,0,0.35)'
            : getElevation(),
          transform: cardSettings.enableHoverEffects ? 'translateY(-8px)' : 'none',
        }
      }}>
        <CardMediaWrapper>
          <StyledCardMedia
            src={imageError ? getFallbackImage() : (image || getFallbackImage())}
            alt={title}
            onError={(e) => { 
              console.error('Image load error:', image);
              setImageError(true);
              const target = e.target as HTMLImageElement;
              target.onerror = null;
              target.src = getFallbackImage();
            }}
          />
          
          {cardSettings.showPrice && (
            <PriceChip 
              label={`${formattedPrice} ₽`}
              icon={<Sell fontSize="small" />}
              sx={{ 
                background: company?.color 
                  ? `linear-gradient(90deg, ${company.color} 0%, ${alpha(company.color, 0.8)} 100%)`
                  : undefined
              }}
            />
          )}
          
          {cardSettings.enableFavorites && (
            <FavoriteButton 
              onClick={handleFavoriteClick} 
              aria-label="добавить в избранное"
              size="small"
            >
              {favorite ? <Favorite color="error" /> : <FavoriteBorder />}
            </FavoriteButton>
          )}
          
          {statusInfo && (
            <StatusBadge color={statusInfo.color}>
              {statusInfo.icon}
              {statusInfo.label}
            </StatusBadge>
          )}
          
          {company && cardSettings.showCompanyLogo && (
            <CompanyLogo 
              src={company.logo} 
              alt={company.name}
              sx={{ border: `3px solid ${company.color || theme.palette.background.paper}` }}
            />
          )}
          
          <IconContainer>
            {getItemTypeIcon()}
          </IconContainer>
        </CardMediaWrapper>
        
        <CardDetailsContainer>
          <Box sx={{ display: 'flex', alignItems: 'flex-start', mb: 2 }}>
            {company && cardSettings.showCompanyLogo && (
              <Box sx={{ 
                flex: '0 0 auto', 
                width: 40, 
                mr: 1.5, 
                visibility: 'hidden' 
              }} />
            )}
            <Box sx={{ flex: 1 }}>
              <Typography 
                gutterBottom 
                variant="h6" 
                component="div" 
                sx={{ 
                  fontWeight: 700, 
                  mb: 1.5,
                  display: '-webkit-box',
                  overflow: 'hidden',
                  WebkitBoxOrient: 'vertical',
                  WebkitLineClamp: 1,
                  color: company?.color || theme.palette.text.primary,
                  fontSize: '1.2rem'
                }}
              >
                {title}
              </Typography>
              
              <Typography 
                variant="body2" 
                color="text.secondary" 
                sx={{ 
                  mb: 2.5,
                  display: '-webkit-box',
                  overflow: 'hidden',
                  WebkitBoxOrient: 'vertical',
                  WebkitLineClamp: 2,
                  lineHeight: 1.5,
                  flexGrow: 1,
                  minHeight: '3rem'
                }}
              >
                {description}
              </Typography>
            </Box>
          </Box>
          
          <Box sx={{ display: 'flex', flexWrap: 'wrap', mb: 2 }}>
            <InfoChip
              size="small"
              icon={<CalendarMonth />}
              label={`${year} год`}
            />
            
            <InfoChip
              size="small"
              icon={<PeopleAlt />}
              label={`${participants} участников`}
            />
          </Box>
          
          <Divider sx={{ mb: 2, opacity: 0.7 }} />
          
          <Box sx={{ mt: 'auto' }}>
            {cardSettings.showProgress && (
              <Box sx={{ mb: 2.5 }}>
                <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 0.8 }}>
                  <Typography variant="caption" color="text.secondary" fontWeight={500}>
                    Продано {ticketsSold} из {totalTickets}
                  </Typography>
                  <Typography variant="caption" sx={{ 
                    fontWeight: 600,
                    color: progress > 80 ? theme.palette.error.main : 
                           progress > 50 ? theme.palette.warning.main : 
                           theme.palette.success.main
                  }}>
                    {progress.toFixed(0)}%
                  </Typography>
                </Box>
                <LinearProgress 
                  variant="determinate" 
                  value={progress} 
                  sx={{ 
                    height: 10, 
                    borderRadius: 5, 
                    mt: 0.7,
                    mb: 1.5,
                    backgroundColor: alpha(primaryColor || theme.palette.primary.main, 0.15),
                    '& .MuiLinearProgress-bar': {
                      borderRadius: 5,
                      background: company?.color 
                        ? `linear-gradient(90deg, ${alpha(company.color, 0.9)} 0%, ${alpha(company.color, 0.7)} 100%)`
                        : `linear-gradient(90deg, ${getProgressColor()} 0%, ${alpha(getProgressColor(), 0.7)} 100%)`,
                    }
                  }} 
                />
                <Typography 
                  variant="body2" 
                  color="text.secondary"
                  sx={{ 
                    display: 'flex', 
                    alignItems: 'center',
                    fontWeight: 500,
                    mb: 2,
                    '& svg': { 
                      fontSize: 16, 
                      mr: 0.5, 
                      color: isEndingSoon ? theme.palette.error.main : theme.palette.text.secondary 
                    }
                  }}
                >
                  <CalendarMonth fontSize="small" />
                  До {formattedEndDate}
                </Typography>
              </Box>
            )}
            
            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1.5 }}>
              <motion.div whileTap={{ scale: 0.95 }}>
                <BuyButton 
                  variant="contained" 
                  size="medium" 
                  startIcon={<LocalOffer fontSize="small" />}
                  disabled={status !== 'active'}
                  sx={{ 
                    background: company?.color 
                      ? `linear-gradient(90deg, ${company.color} 0%, ${alpha(company.color, 0.8)} 100%)`
                      : undefined,
                    opacity: status !== 'active' ? 0.6 : 1,
                    width: '100%',
                    py: 1.2,
                    fontSize: '0.95rem'
                  }}
                >
                  Купить билет
                </BuyButton>
              </motion.div>
            
              <motion.div whileTap={{ scale: 0.95 }}>
                <Button 
                  variant="outlined" 
                  size="medium" 
                  component={Link}
                  to={`/raffles/${id}`}
                  endIcon={<ArrowForward fontSize="small" />}
                  sx={{ 
                    width: '100%',
                    py: 1.2,
                    fontSize: '0.9rem',
                    borderRadius: 100,
                    borderColor: company?.color ? alpha(company.color, 0.5) : undefined,
                    color: company?.color || theme.palette.primary.main,
                    '&:hover': {
                      borderColor: company?.color || theme.palette.primary.main,
                      backgroundColor: alpha(company?.color || theme.palette.primary.main, 0.04),
                      transform: 'translateY(-2px)',
                    }
                  }}
                >
                  Подробнее
                </Button>
              </motion.div>
            </Box>
          </Box>
        </CardDetailsContainer>
      </StyledCard>
    </MotionCard>
  );
};

export default CarCard;
